    const uplinkGrid = document.getElementById('uplink-grid');
    const uplinkSearch = document.getElementById('uplink-search');
    const filterBtns = document.querySelectorAll('.filter-btn');
    const totalLinksEl = document.getElementById('total-links');
    function renderLinks(filter = 'all', search = '') {
        if (!uplinkGrid) return;
        uplinkGrid.innerHTML = '';

        let filtered = links.filter(link => {
            const matchFilter = filter === 'all' || link.cat === filter;
            const matchSearch = link.name.toLowerCase().includes(search.toLowerCase());
            return matchFilter && matchSearch;
        });

        if (filter === 'all') {
            filtered.sort((a, b) => a.name.localeCompare(b.name));
        }

        if (totalLinksEl) totalLinksEl.textContent = `${filtered.length} LINKS`;

        filtered.forEach(link => {
            const card = document.createElement('a');
            card.href = link.url;
            card.target = '_blank';
            card.className = 'link-card';
            card.innerHTML = `
                <div>
                    <div class="link-title">${link.name}</div>
                    <div class="link-url">${new URL(link.url).hostname}</div>
                </div>
                <div class="link-cat">${link.cat.toUpperCase()}</div>
            `;
            uplinkGrid.appendChild(card);
        });
    }

    filterBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            filterBtns.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            const filter = btn.getAttribute('data-filter');
            renderLinks(filter, uplinkSearch.value);
        });
    });

    if (uplinkSearch) {
        uplinkSearch.addEventListener('input', (e) => {
            const activeFilter = document.querySelector('.filter-btn.active');
            const filter = activeFilter ? activeFilter.getAttribute('data-filter') : 'all';
            renderLinks(filter, e.target.value);
        });
    }

    // Initial Render
    renderLinks();

